-- ============================================================
-- SÃO RAFAEL - DATABASE SETUP (Full Reset + Migration)
-- Executes all migrations in sequence
-- ============================================================

-- Enable required extensions
CREATE EXTENSION IF NOT EXISTS vector;
CREATE EXTENSION IF NOT EXISTS pg_trgm;
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- ============================================
-- 1. BASE TABLES (001)
-- ============================================
CREATE TABLE IF NOT EXISTS saorafael_users (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  email TEXT UNIQUE NOT NULL,
  full_name TEXT,
  role TEXT DEFAULT 'usuario' CHECK (role IN ('admin','usuario','visualizador')),
  confirmed BOOLEAN DEFAULT FALSE,
  company_name TEXT DEFAULT 'saorafael',
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS saorafael_wizard_submission (
  id BIGSERIAL PRIMARY KEY,
  session_id TEXT UNIQUE,
  user_id UUID REFERENCES auth.users(id) ON DELETE SET NULL,
  client_id UUID,
  form_data JSONB NOT NULL DEFAULT '{}',
  status TEXT DEFAULT 'submitted' CHECK (status IN ('submitted','processing','completed','error')),
  protocol TEXT,
  submitted_at TIMESTAMPTZ DEFAULT NOW(),
  processed_at TIMESTAMPTZ,
  notes TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS saorafael_chat_message (
  id BIGSERIAL PRIMARY KEY,
  session_id TEXT NOT NULL,
  user_id UUID REFERENCES auth.users(id) ON DELETE SET NULL,
  message JSONB NOT NULL DEFAULT '{}',
  created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================
-- 2. CLIENTS TABLE (011)
-- ============================================
CREATE TABLE IF NOT EXISTS saorafael_clients (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  razao_social TEXT NOT NULL,
  cnpj_cpf TEXT,
  inscricao_estadual TEXT,
  endereco TEXT,
  cidade TEXT,
  estado TEXT,
  cep TEXT,
  contato_nome TEXT,
  contato_telefone TEXT,
  contato_email TEXT,
  dados_tecnicos TEXT,
  local_instalacao TEXT,
  telefone TEXT,
  email TEXT,
  created_by UUID REFERENCES auth.users(id) ON DELETE SET NULL,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Indexes for fast search
CREATE INDEX IF NOT EXISTS idx_saorafael_clients_razao_social_trgm
  ON saorafael_clients USING gin (razao_social gin_trgm_ops);
CREATE INDEX IF NOT EXISTS idx_saorafael_clients_cnpj_cpf
  ON saorafael_clients (cnpj_cpf);
CREATE INDEX IF NOT EXISTS idx_saorafael_clients_cidade
  ON saorafael_clients (cidade);

-- client_id column on submissions (safe IF NOT EXISTS)
DO $$ BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'saorafael_wizard_submission' AND column_name = 'client_id'
  ) THEN
    ALTER TABLE saorafael_wizard_submission ADD COLUMN client_id UUID;
  END IF;
END $$;

-- ============================================
-- 3. VECTOR STORE: TRUNCATE + RECREATE (RAG Reset)
-- ============================================
TRUNCATE TABLE saorafael_documents;

-- Ensure the match function exists
CREATE OR REPLACE FUNCTION saorafael_match_documents (
  query_embedding vector(1536),
  match_count int DEFAULT NULL,
  filter jsonb DEFAULT '{}'
) RETURNS TABLE (
  id bigint,
  content text,
  metadata jsonb,
  similarity float
)
LANGUAGE plpgsql
AS $$
#variable_conflict use_column
BEGIN
  RETURN QUERY
  SELECT
    id,
    content,
    metadata,
    1 - (saorafael_documents.embedding <=> query_embedding) AS similarity
  FROM saorafael_documents
  WHERE metadata @> filter
  ORDER BY saorafael_documents.embedding <=> query_embedding
  LIMIT match_count;
END;
$$;

-- ============================================
-- 4. CHAT HISTORY: TRUNCATE
-- ============================================
TRUNCATE TABLE saorafael_chat_message;

-- ============================================
-- 5. RLS POLICIES
-- ============================================
ALTER TABLE saorafael_wizard_submission ENABLE ROW LEVEL SECURITY;
ALTER TABLE saorafael_chat_message ENABLE ROW LEVEL SECURITY;
ALTER TABLE saorafael_clients ENABLE ROW LEVEL SECURITY;

-- Clients RLS
DO $$ BEGIN
  DROP POLICY IF EXISTS saorafael_clients_select_policy ON saorafael_clients;
  DROP POLICY IF EXISTS saorafael_clients_insert_policy ON saorafael_clients;
  DROP POLICY IF EXISTS saorafael_clients_update_policy ON saorafael_clients;
  DROP POLICY IF EXISTS saorafael_clients_delete_policy ON saorafael_clients;

  CREATE POLICY saorafael_clients_select_policy ON saorafael_clients
    FOR SELECT TO authenticated USING (true);
  CREATE POLICY saorafael_clients_insert_policy ON saorafael_clients
    FOR INSERT TO authenticated WITH CHECK (created_by = auth.uid());
  CREATE POLICY saorafael_clients_update_policy ON saorafael_clients
    FOR UPDATE TO authenticated USING (
      created_by = auth.uid()
      OR EXISTS (SELECT 1 FROM auth.users u WHERE u.id = auth.uid() AND u.raw_user_meta_data->>'role' = 'admin')
    );
  CREATE POLICY saorafael_clients_delete_policy ON saorafael_clients
    FOR DELETE TO authenticated USING (
      EXISTS (SELECT 1 FROM auth.users u WHERE u.id = auth.uid() AND u.raw_user_meta_data->>'role' = 'admin')
    );
END $$;

-- Submissions RLS
DO $$ BEGIN
  DROP POLICY IF EXISTS saorafael_submission_select_all ON saorafael_wizard_submission;
  DROP POLICY IF EXISTS saorafael_submission_insert ON saorafael_wizard_submission;
  DROP POLICY IF EXISTS saorafael_submission_update ON saorafael_wizard_submission;
  DROP POLICY IF EXISTS saorafael_submission_delete ON saorafael_wizard_submission;

  CREATE POLICY saorafael_submission_select_all ON saorafael_wizard_submission
    FOR SELECT TO authenticated USING (true);
  CREATE POLICY saorafael_submission_insert ON saorafael_wizard_submission
    FOR INSERT TO authenticated WITH CHECK (true);
  CREATE POLICY saorafael_submission_update ON saorafael_wizard_submission
    FOR UPDATE TO authenticated USING (
      user_id = auth.uid()
      OR EXISTS (SELECT 1 FROM auth.users u WHERE u.id = auth.uid() AND u.raw_user_meta_data->>'role' = 'admin')
    );
  CREATE POLICY saorafael_submission_delete ON saorafael_wizard_submission
    FOR DELETE TO authenticated USING (
      EXISTS (SELECT 1 FROM auth.users u WHERE u.id = auth.uid() AND u.raw_user_meta_data->>'role' = 'admin')
    );
END $$;

-- Chat RLS
DO $$ BEGIN
  DROP POLICY IF EXISTS saorafael_chat_select ON saorafael_chat_message;
  DROP POLICY IF EXISTS saorafael_chat_insert ON saorafael_chat_message;
  DROP POLICY IF EXISTS saorafael_chat_delete ON saorafael_chat_message;

  CREATE POLICY saorafael_chat_select ON saorafael_chat_message
    FOR SELECT TO authenticated USING (user_id = auth.uid() OR EXISTS (SELECT 1 FROM auth.users u WHERE u.id = auth.uid() AND u.raw_user_meta_data->>'role' = 'admin'));
  CREATE POLICY saorafael_chat_insert ON saorafael_chat_message
    FOR INSERT TO authenticated WITH CHECK (true);
  CREATE POLICY saorafael_chat_delete ON saorafael_chat_message
    FOR DELETE TO authenticated USING (user_id = auth.uid() OR EXISTS (SELECT 1 FROM auth.users u WHERE u.id = auth.uid() AND u.raw_user_meta_data->>'role' = 'admin'));
END $$;

-- Service role bypass
DO $$ BEGIN
  DROP POLICY IF EXISTS saorafael_clients_service_role ON saorafael_clients;
  DROP POLICY IF EXISTS saorafael_submission_service_role ON saorafael_wizard_submission;
  DROP POLICY IF EXISTS saorafael_chat_service_role ON saorafael_chat_message;

  CREATE POLICY saorafael_clients_service_role ON saorafael_clients
    FOR ALL TO service_role USING (true) WITH CHECK (true);
  CREATE POLICY saorafael_submission_service_role ON saorafael_wizard_submission
    FOR ALL TO service_role USING (true) WITH CHECK (true);
  CREATE POLICY saorafael_chat_service_role ON saorafael_chat_message
    FOR ALL TO service_role USING (true) WITH CHECK (true);
END $$;

-- Return confirmation
SELECT 'Database setup completed successfully' AS result, NOW() AS executed_at;
